    <div id="stats"></div>
    <div id="room"></div>
    <div id="scene"></div>
    <div id="controls"></div>
    <script>
        const player = {
            name: "Erik",
            PAge: 18,
            MAge: 18,
            height: 175,
            weight: 155,
            inventory: [],
            mentalTraits: [],
            physicalTraits: [],
