            },
        };

        const storageBoxes = {
            storageBoxDaycare: {
                name: "storage box (daycare)",
                isOpen: false,
                inventory: ["mentalAgePotion", "battleArmor"],
                location: "daycare",
                descriptionOpen: "There is a cute open playful box in the corner.",
                descriptionClosed: "There is a cute closed playful box in the corner.",
            },
            storageBoxPlayroom: {
                name: "storage box (playroom)",
                isOpen: false,
                inventory: [],
                location: "playroom",
                descriptionOpen: "An open empty box.",
                descriptionClosed: "A closed box.",
            },
        };

        let currentRoom = "daycare";

        function describeRoom() {
            const roomDiv = document.getElementById("room");
            const room = rooms[currentRoom];
            let itemsDescription = "";
            if (room.interactiveItems.length > 0) {
                itemsDescription += "<br />";
            }
            room.interactiveItems.forEach(itemId => {
                const storageBox = storageBoxes[itemId];
                if (storageBox && storageBox.location === currentRoom) {
                    itemsDescription += storageBox.isOpen ? storageBox.descriptionOpen : storageBox.descriptionClosed;
                    itemsDescription += "<br />";
                }
            });
            roomDiv.innerHTML = `
            <strong>${room.name.toUpperCase()}</strong>
            <br />
            ${room.description}
            ${itemsDescription}
            `;
        }

        function describeScene() {
            const sceneDiv = document.getElementById("scene");
            const room = rooms[currentRoom];
            let html = `
                <p>You are in the ${room.name}. ${room.description}</p>
                <ul>`;
            room.interactiveItems.forEach(itemId => {
                const storageBox = storageBoxes[itemId];
                const item = items[itemId];
                if (storageBox && storageBox.location === currentRoom) {
                    html += `<li>${storageBox.isOpen ? storageBox.descriptionOpen : storageBox.descriptionClosed}</li>`;
                } else if (item) {
                    html += `<li>${item.name}: ${item.description}</li>`;
                }
            });
            html += "</ul>";
            sceneDiv.innerHTML = html;
        }

        function move(direction) {
            const room = rooms[currentRoom];
            const newRoom = room[direction];
            if (newRoom) {
                currentRoom = newRoom;
                describeRoom();
                describeScene();
            }
        }

        function toggleStorageBox(storageBoxId) {
            const storageBox = storageBoxes[storageBoxId];
            storageBox.isOpen = !storageBox.isOpen;
            describeRoom();
            describeScene();
        }

        function renderControls() {
            const room = rooms[currentRoom];
            const controlsDiv = document.getElementById("controls");

            const northButton = document.createElement("button");
            northButton.innerText = "Go North";
            northButton.disabled = !room.north;
            northButton.onclick = () => move("north");
            const southButton = document.createElement("button");
            southButton.innerText = "Go South";
            southButton.disabled = !room.north;
            southButton.onclick = () => move("south");
            const eastButton = document.createElement("button");
            eastButton.innerText = "Go East";
            eastButton.disabled = !room.east;
            eastButton.onclick = () => move("east");
            const westButton = document.createElement("button");
            westButton.innerText = "Go West";
            westButton.disabled = !room.west;
            westButton.onclick = () => move("west");

            controlsDiv.appendChild(northButton);
            controlsDiv.appendChild(southButton);
            controlsDiv.appendChild(eastButton);
            controlsDiv.appendChild(westButton);

            if (room.interactiveItems.length > 0) {
                room.interactiveItems.forEach(itemId => {
                    const storageBox = storageBoxes[itemId];
                    if (storageBox && storageBox.location === currentRoom) {
                        const storageButton = document.createElement("button");
                        storageButton.innerText = storageBox.isOpen ? "Close box" : "Open box";
                        storageButton.onclick = () => toggleStorageBox(itemId);
                        controlsDiv.appendChild(storageButton);
                    }
                });
            }
        }

        function initializeGame() {
            updateStats();
            describeRoom();
            describeScene();
            renderControls();
        }

        initializeGame();

    </script>
</body>
</html>
```

